import React from 'react';
import { 
  LayoutDashboard, 
  Lightbulb, 
  FileText, 
  Search, 
  Image as ImageIcon,
  Menu,
  X,
  LogOut,
  CreditCard,
  Copy,
  Gift,
  CalendarRange,
  Twitter,
  Linkedin,
  Youtube,
  ChevronRight,
  Video,
  Mic,
  BrainCircuit,
  Radio,
  Eye,
  UserCheck,
  ClipboardCheck,
  Repeat,
  TrendingUp,
  Tag,
  Type,
  Send,
  Users,
  Mail,
  LineChart,
  FolderKanban
} from 'lucide-react';
import { ToolType, NavItem } from '../types';
import { useAuth } from '../auth/AuthContext';

interface LayoutProps {
  currentTool: ToolType;
  onNavigate: (tool: ToolType) => void;
  children: React.ReactNode;
}

const NAV_ITEMS: NavItem[] = [
  { id: ToolType.DASHBOARD, label: 'Dashboard', icon: <LayoutDashboard size={20} /> },
  { id: ToolType.PROJECTS, label: 'Projects & Workspace', icon: <FolderKanban size={20} /> },
  { id: ToolType.IDEAS, label: 'Idea Generator', icon: <Lightbulb size={20} /> },
  { id: ToolType.SCRIPT, label: 'Script Writer', icon: <FileText size={20} /> },
  { id: ToolType.RESEARCH, label: 'Research Assistant', icon: <BrainCircuit size={20} /> },
  { id: ToolType.MARKET_STRATEGIST, label: 'Market Strategist', icon: <LineChart size={20} /> },
  { id: ToolType.REPURPOSE, label: 'Repurpose Engine', icon: <Repeat size={20} /> },
  { id: ToolType.COMPETITOR_SPY, label: 'Competitor Spy', icon: <UserCheck size={20} /> },
  { id: ToolType.KEYWORD_INSPECTOR, label: 'Keyword Inspector', icon: <Tag size={20} /> },
  { id: ToolType.TREND_WATCHER, label: 'Trend Watcher', icon: <TrendingUp size={20} /> },
  { id: ToolType.TITLE_GENERATOR, label: 'Title Generator', icon: <Type size={20} /> },
  { id: ToolType.SEO, label: 'SEO Optimizer', icon: <Search size={20} /> },
  { id: ToolType.CHANNEL_AUDIT, label: 'Channel Audit', icon: <ClipboardCheck size={20} /> },
  { id: ToolType.OUTREACH, label: 'Outreach Hub', icon: <Users size={20} /> },
  { id: ToolType.EMAIL_MARKETING, label: 'Email Blast Studio', icon: <Mail size={20} /> },
  { id: ToolType.THUMBNAIL, label: 'Thumbnail Studio', icon: <ImageIcon size={20} /> },
  { id: ToolType.THUMBNAIL_RATER, label: 'Thumbnail Rater', icon: <Eye size={20} /> },
  { id: ToolType.VIDEO, label: 'Video Studio', icon: <Video size={20} /> },
  { id: ToolType.AUDIO, label: 'Audio Studio', icon: <Mic size={20} /> },
  { id: ToolType.MARKETING, label: 'Marketing Scheduler', icon: <CalendarRange size={20} /> },
  { id: ToolType.LIVE, label: 'Live Brainstorm', icon: <Radio size={20} /> },
];

export const Layout: React.FC<LayoutProps> = ({ currentTool, onNavigate, children }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');
  const searchInputRef = React.useRef<HTMLInputElement>(null);
  const { user, logout, checkPlanStatus } = useAuth();
  const { daysLeft, isFree } = checkPlanStatus();

  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        searchInputRef.current?.focus();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleCopyReferral = () => {
    if (user?.referralCode) {
      navigator.clipboard.writeText(`https://ranktica.ai/signup?ref=${user.referralCode}`);
      alert("Referral link copied!");
    }
  };

  const filteredTools = NAV_ITEMS.filter(item => 
    item.label.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex h-screen bg-[#09090b] text-white overflow-hidden">
      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex w-64 flex-col border-r border-zinc-800 bg-[#0f0f12]">
        <div className="p-6">
          <h1 className="text-2xl font-bold bg-gradient-to-r from-red-500 to-orange-500 bg-clip-text text-transparent">
            Ranktica AI
          </h1>
          <p className="text-xs text-zinc-500 mt-1">Creator Automation Suite</p>
        </div>

        <nav className="flex-1 px-3 space-y-1 overflow-y-auto">
          {NAV_ITEMS.map((item) => (
            <button
              key={item.id}
              onClick={() => onNavigate(item.id)}
              className={`flex items-center w-full px-4 py-2.5 text-sm font-medium rounded-xl transition-all duration-200 ${
                currentTool === item.id 
                  ? 'bg-red-500/10 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.2)] border border-red-500/20' 
                  : 'text-zinc-400 hover:bg-zinc-800 hover:text-white'
              }`}
            >
              <span className="mr-3">{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>

        {/* User Profile & Plan Status */}
        <div className="p-4 border-t border-zinc-800 space-y-4">
           {/* Referral Section */}
           <div className="p-3 rounded-lg bg-zinc-900 border border-zinc-800">
             <div className="flex items-center justify-between mb-2">
               <span className="text-xs font-semibold text-zinc-400 flex items-center gap-1"><Gift size={12}/> Referral</span>
               <button onClick={handleCopyReferral} className="text-zinc-500 hover:text-white"><Copy size={12}/></button>
             </div>
             <code className="block text-xs text-center bg-black/50 p-1.5 rounded text-red-400 font-mono">
               {user?.referralCode || '----'}
             </code>
           </div>

           {/* Plan Status */}
           <div className="flex flex-col gap-2 p-3 rounded-lg bg-zinc-900/50 border border-zinc-800">
              <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-xs ${isFree ? 'bg-zinc-700 text-zinc-300' : 'bg-gradient-to-tr from-blue-500 to-purple-500 text-white'}`}>
                  {isFree ? 'TRIAL' : 'PRO'}
                </div>
                <div className="flex-1 overflow-hidden">
                   <p className="text-sm font-medium truncate">{user?.name}</p>
                   <p className="text-xs text-zinc-500">{daysLeft} days left</p>
                </div>
              </div>

              {isFree && (
                <button 
                  onClick={() => onNavigate(ToolType.UPGRADE)}
                  className="w-full text-xs bg-red-600 hover:bg-red-500 text-white py-1.5 rounded transition-colors flex items-center justify-center gap-1"
                >
                  <CreditCard size={12} /> Upgrade Now
                </button>
              )}
           </div>

           <button 
             onClick={logout}
             className="w-full flex items-center justify-center gap-2 text-sm text-zinc-500 hover:text-white transition-colors py-2"
           >
             <LogOut size={16} /> Sign Out
           </button>

           {/* Social Links */}
           <div className="flex justify-center gap-4 pt-2 border-t border-zinc-800/50 mt-2">
              <a href="https://twitter.com/rankticaai" target="_blank" rel="noopener noreferrer" className="text-zinc-600 hover:text-[#1DA1F2] transition-colors" title="Twitter">
                <Twitter size={16} />
              </a>
              <a href="https://linkedin.com/company/rankticaai" target="_blank" rel="noopener noreferrer" className="text-zinc-600 hover:text-[#0A66C2] transition-colors" title="LinkedIn">
                <Linkedin size={16} />
              </a>
              <a href="https://youtube.com/@rankticaai" target="_blank" rel="noopener noreferrer" className="text-zinc-600 hover:text-[#FF0000] transition-colors" title="YouTube">
                <Youtube size={16} />
              </a>
           </div>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full z-50 bg-[#0f0f12] border-b border-zinc-800 px-4 py-3 flex items-center justify-between">
         <h1 className="text-xl font-bold text-red-500">Ranktica AI</h1>
         <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-zinc-400">
            {isMobileMenuOpen ? <X /> : <Menu />}
         </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 z-40 bg-black/90 md:hidden pt-20 px-6 overflow-y-auto">
           <nav className="space-y-2 pb-8">
            {NAV_ITEMS.map((item) => (
                <button
                key={item.id}
                onClick={() => {
                  onNavigate(item.id);
                  setIsMobileMenuOpen(false);
                }}
                className={`flex items-center w-full px-4 py-4 text-lg font-medium rounded-lg ${
                  currentTool === item.id 
                    ? 'bg-red-500/10 text-red-500' 
                    : 'text-zinc-400'
                }`}
              >
                <span className="mr-4">{item.icon}</span>
                {item.label}
              </button>
            ))}
            <div className="border-t border-zinc-800 my-4 pt-4">
              <button onClick={() => onNavigate(ToolType.UPGRADE)} className="w-full py-4 text-left text-yellow-500 font-medium">Upgrade Plan</button>
              <button onClick={logout} className="w-full py-4 text-left text-zinc-400">Sign Out</button>
            </div>
           </nav>
        </div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col relative overflow-hidden pt-16 md:pt-0 bg-[#09090b]">

        {/* Desktop Header with Search */}
        <header className="hidden md:flex items-center justify-between px-8 py-4 border-b border-zinc-800 bg-[#0f0f12]/80 backdrop-blur-md sticky top-0 z-30">
            <div className="flex items-center text-sm font-medium text-zinc-400">
               <span className="hover:text-white cursor-pointer transition-colors" onClick={() => onNavigate(ToolType.DASHBOARD)}>Ranktica AI</span>
               <ChevronRight size={14} className="mx-2 text-zinc-600" />
               <span className="text-white bg-zinc-800/50 px-2 py-0.5 rounded text-xs">{NAV_ITEMS.find(n => n.id === currentTool)?.label || 'Dashboard'}</span>
            </div>

            <div className="relative group z-50">
               <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500 group-focus-within:text-red-500 transition-colors" size={16} />
                  <input 
                      ref={searchInputRef}
                      type="text"
                      placeholder="Search tools... (Cmd+K)"
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="w-64 focus:w-80 bg-zinc-900/50 border border-zinc-800 hover:border-zinc-700 focus:border-red-500/50 rounded-full pl-10 pr-4 py-2 text-sm text-white outline-none transition-all placeholder:text-zinc-600"
                  />
               </div>

               {/* Search Results Dropdown */}
               {searchQuery && (
                  <>
                    <div className="fixed inset-0 z-40" onClick={() => setSearchQuery('')}></div>
                    <div className="absolute top-full right-0 mt-2 w-80 bg-[#0f0f12] border border-zinc-800 rounded-xl shadow-2xl overflow-hidden ring-1 ring-white/10 z-50 animate-in fade-in zoom-in-95 duration-100">
                        {filteredTools.length > 0 ? (
                            <div className="py-2">
                                <h3 className="px-4 py-2 text-xs font-bold text-zinc-500 uppercase tracking-wider">Tools</h3>
                                {filteredTools.map(item => (
                                    <button
                                        key={item.id}
                                        onClick={() => {
                                            onNavigate(item.id);
                                            setSearchQuery('');
                                        }}
                                        className="w-full text-left px-4 py-3 hover:bg-zinc-800 flex items-center gap-3 transition-colors group border-l-2 border-transparent hover:border-red-500"
                                    >
                                        <span className="text-zinc-400 group-hover:text-red-500 transition-colors">{item.icon}</span>
                                        <span className="text-zinc-200 group-hover:text-white text-sm font-medium">{item.label}</span>
                                    </button>
                                ))}
                            </div>
                        ) : (
                            <div className="p-8 text-center flex flex-col items-center gap-2">
                                <Search className="text-zinc-700" size={24} />
                                <p className="text-sm text-zinc-500">No results found for "{searchQuery}"</p>
                            </div>
                        )}
                    </div>
                  </>
               )}
            </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-6xl mx-auto h-full">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { UserPlus, LogIn, Youtube, Gift } from 'lucide-react';

export const Auth: React.FC = () => {
  const { login, signup } = useAuth();
  const [isLogin, setIsLogin] = useState(true);

  // Form State
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [referral, setReferral] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isLogin) {
      login(email);
    } else {
      signup(email, name, referral);
    }
  };

  return (
    <div className="min-h-screen bg-[#09090b] flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <div className="flex justify-center mb-4">
            <div className="w-16 h-16 bg-gradient-to-tr from-red-600 to-orange-600 rounded-2xl flex items-center justify-center shadow-lg shadow-red-500/20">
              <Youtube size={32} className="text-white" />
            </div>
          </div>
          <h1 className="text-3xl font-bold text-white mb-2">Ranktica AI</h1>
          <p className="text-zinc-400">
            {isLogin ? 'Welcome back, Creator.' : 'Start your viral journey.'}
          </p>
        </div>

        <div className="bg-[#0f0f12] border border-zinc-800 rounded-2xl p-8 shadow-2xl">
          <form onSubmit={handleSubmit} className="space-y-4">
            {!isLogin && (
              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">Full Name</label>
                <input
                  type="text"
                  required
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 outline-none transition-all"
                  placeholder="Mr. Beast"
                />
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-zinc-400 mb-1">Email Address</label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 outline-none transition-all"
                placeholder="creator@example.com"
              />
            </div>

            {!isLogin && (
              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">Referral Code (Optional)</label>
                <div className="relative">
                  <input
                    type="text"
                    value={referral}
                    onChange={(e) => setReferral(e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 outline-none transition-all pl-10"
                    placeholder="FRIEND123"
                  />
                  <Gift size={18} className="absolute left-3 top-3.5 text-zinc-500" />
                </div>
              </div>
            )}

            <button
              type="submit"
              className="w-full bg-red-600 hover:bg-red-500 text-white font-bold py-3 rounded-xl transition-all shadow-[0_0_20px_rgba(220,38,38,0.3)] hover:shadow-[0_0_30px_rgba(220,38,38,0.5)] flex items-center justify-center gap-2 mt-6"
            >
              {isLogin ? (
                <>
                  <LogIn size={20} /> Login
                </>
              ) : (
                <>
                  <UserPlus size={20} /> Create Account
                </>
              )}
            </button>
          </form>

          <div className="mt-6 pt-6 border-t border-zinc-800 text-center">
            <button
              onClick={() => setIsLogin(!isLogin)}
              className="text-zinc-500 hover:text-white text-sm transition-colors"
            >
              {isLogin ? "Don't have an account? Sign up" : "Already have an account? Login"}
            </button>
          </div>
        </div>

        {!isLogin && (
          <p className="text-center text-xs text-zinc-600 mt-6">
            By signing up, you agree to our Terms. You will receive a 3-Day Free Trial.
          </p>
        )}
      </div>
    </div>
  );
};

