  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return;

    const newProject: Project = {
      id: Date.now().toString(),
      title: newProjectName,
      niche: newProjectNiche || 'General',
      status: 'idea',
      lastUpdated: Date.now(),
      assets: {},
      team: []
    };

    saveProjects([newProject, ...projects]);
    setIsCreating(false);
    setNewProjectName('');
    setNewProjectNiche('');
  };

  const updateStatus = (id: string, newStatus: Project['status']) => {
    const updated = projects.map(p => p.id === id ? { ...p, status: newStatus, lastUpdated: Date.now() } : p);
    saveProjects(updated);
  };

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this project?")) {
      saveProjects(projects.filter(p => p.id !== id));
    }
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(`https://ranktica.ai/p/${shareProject?.id}/share?token=xyz123`);
    setCopiedLink(true);
    setTimeout(() => setCopiedLink(false), 2000);
  };

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (inviteEmail && shareProject) {
      alert(`Invitation sent to ${inviteEmail}`);
      setInviteEmail('');
      setShareProject(null);
    }
  };

  const columns = [
    { id: 'idea', label: 'Idea / Planning', color: 'bg-zinc-500' },
    { id: 'scripting', label: 'Scripting', color: 'bg-blue-500' },
    { id: 'production', label: 'Production', color: 'bg-orange-500' },
    { id: 'scheduled', label: 'Scheduled', color: 'bg-purple-500' },
    { id: 'published', label: 'Published', color: 'bg-green-500' }
  ];

  return (
    <div className="h-full flex flex-col space-y-6 animate-fade-in pb-10">
      <div className="flex justify-between items-center shrink-0">
         <div>
            <h2 className="text-3xl font-bold text-white">Projects & Workspace</h2>
            <p className="text-zinc-400">Manage your video pipeline and collaborate with your team.</p>
         </div>
         <button 
           onClick={() => setIsCreating(true)}
           className="bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-xl font-bold shadow-lg shadow-red-600/20 flex items-center gap-2"
         >
           <Plus size={20} /> New Project
         </button>
      </div>

      {isCreating && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
           <form onSubmit={handleCreate} className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 w-full max-w-md shadow-2xl animate-fade-in">
              <h3 className="text-xl font-bold text-white mb-4">Create New Project</h3>
              <div className="space-y-4">
                 <div>
                    <label className="text-sm text-zinc-400 block mb-1">Project Title</label>
                    <input 
                      value={newProjectName}
                      onChange={e => setNewProjectName(e.target.value)}
                      placeholder="e.g. My Next Viral Hit"
                      className="w-full bg-zinc-950 border border-zinc-800 rounded-xl p-3 text-white focus:ring-2 focus:ring-red-500/50 outline-none"
                      autoFocus
                    />
                 </div>
                 <div>
                    <label className="text-sm text-zinc-400 block mb-1">Niche / Category</label>
                    <input 
                      value={newProjectNiche}
                      onChange={e => setNewProjectNiche(e.target.value)}
                      placeholder="e.g. Gaming"
                      className="w-full bg-zinc-950 border border-zinc-800 rounded-xl p-3 text-white focus:ring-2 focus:ring-red-500/50 outline-none"
                    />
                 </div>
                 <div className="flex gap-3 mt-6">
                    <button type="button" onClick={() => setIsCreating(false)} className="px-4 py-2 text-zinc-400 hover:text-white">Cancel</button>
                    <button type="submit" disabled={!newProjectName} className="flex-1 bg-red-600 hover:bg-red-500 text-white rounded-xl font-bold">Create Project</button>
                 </div>
              </div>
           </form>
        </div>
      )}

      {/* Share Modal */}
      {shareProject && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
           <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 w-full max-w-md shadow-2xl animate-fade-in">
              <div className="flex justify-between items-start mb-6">
                 <div>
                   <h3 className="text-xl font-bold text-white">Share Workspace</h3>
                   <p className="text-sm text-zinc-400">Collaborate on "{shareProject.title}"</p>
                 </div>
                 <button onClick={() => setShareProject(null)}><XIcon size={20} /></button>
              </div>

              <div className="space-y-6">
                 <div>
                    <label className="text-xs font-bold text-zinc-500 uppercase block mb-2">Invite via Email</label>
                    <form onSubmit={handleInvite} className="flex gap-2">
                       <input 
                         type="email" 
                         value={inviteEmail}
                         onChange={e => setInviteEmail(e.target.value)}
                         placeholder="editor@example.com"
                         className="flex-1 bg-zinc-950 border border-zinc-800 rounded-lg p-2 text-white text-sm outline-none focus:border-blue-500"
                       />
                       <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 rounded-lg text-sm font-medium">Invite</button>
                    </form>
                 </div>

                 <div>
                    <label className="text-xs font-bold text-zinc-500 uppercase block mb-2">Public Link</label>
                    <div className="flex gap-2 bg-zinc-950 border border-zinc-800 p-2 rounded-lg">
                       <div className="flex-1 text-sm text-zinc-400 truncate flex items-center gap-2">
                          <LinkIcon size={14} />
                          https://ranktica.ai/p/{shareProject.id}/share...
                       </div>
                       <button onClick={handleCopyLink} className="text-zinc-400 hover:text-white text-sm font-medium flex items-center gap-1">
                          {copiedLink ? <Check size={14} className="text-green-500" /> : <CopyIcon size={14} />}
                       </button>
                    </div>
                 </div>

                 <div className="bg-zinc-800/50 p-3 rounded-lg flex items-start gap-3">
                    <Users size={16} className="text-zinc-400 mt-1" />
                    <p className="text-xs text-zinc-400">Team members will have full access to Scripts, Thumbnails, and SEO data within this project.</p>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* Kanban Board */}
      <div className="flex-1 overflow-x-auto overflow-y-hidden">
         <div className="flex gap-6 h-full min-w-[1000px] pb-4">
            {columns.map(col => {
               const colProjects = projects.filter(p => p.status === col.id);
               return (
                  <div key={col.id} className="flex-1 flex flex-col min-w-[280px]">
                     <div className="flex items-center justify-between mb-4 px-2">
                        <div className="flex items-center gap-2">
                           <div className={`w-2 h-2 rounded-full ${col.color}`}></div>
                           <h3 className="font-bold text-zinc-300 text-sm">{col.label}</h3>
                           <span className="text-xs text-zinc-500 font-medium px-2 py-0.5 bg-zinc-900 rounded-full">{colProjects.length}</span>
                        </div>
                     </div>

                     <div className="flex-1 bg-zinc-900/30 border border-zinc-800/50 rounded-2xl p-3 space-y-3 overflow-y-auto">
                        {colProjects.map(project => (
                           <div key={project.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 p-4 rounded-xl shadow-sm hover:shadow-lg transition-all group">
                              <div className="flex justify-between items-start mb-2">
                                 <span className="text-[10px] uppercase font-bold text-zinc-500 tracking-wider bg-zinc-950 px-1.5 py-0.5 rounded border border-zinc-800">{project.niche}</span>
                                 <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => setShareProject(project)} className="p-1 hover:bg-zinc-800 rounded text-zinc-500 hover:text-blue-400" title="Share">
                                       <Share2 size={14} />
                                    </button>
                                    <button onClick={() => handleDelete(project.id)} className="p-1 hover:bg-zinc-800 rounded text-zinc-500 hover:text-red-400" title="Delete">
                                       <Trash2 size={14} />
                                    </button>
                                 </div>
                              </div>

                              <h4 className="font-bold text-white mb-3 leading-tight">{project.title}</h4>

                              {/* Assets Indicators */}
                              <div className="flex gap-2 mb-4">
                                 <span className={`p-1 rounded ${project.assets.script ? 'bg-blue-500/20 text-blue-400' : 'bg-zinc-800 text-zinc-600'}`} title="Script"><FileText size={12} /></span>
                                 <span className={`p-1 rounded ${project.assets.thumbnail ? 'bg-orange-500/20 text-orange-400' : 'bg-zinc-800 text-zinc-600'}`} title="Thumbnail"><ImageIcon size={12} /></span>
                                 <span className={`p-1 rounded ${project.assets.seo ? 'bg-green-500/20 text-green-400' : 'bg-zinc-800 text-zinc-600'}`} title="SEO"><Search size={12} /></span>
                                 <span className={`p-1 rounded ${project.assets.video ? 'bg-purple-500/20 text-purple-400' : 'bg-zinc-800 text-zinc-600'}`} title="Video"><Video size={12} /></span>
                              </div>

                              <div className="flex justify-between items-center border-t border-zinc-800 pt-3">
                                 <div className="flex -space-x-2">
                                    {project.team.length > 0 ? project.team.map((avatar, i) => (
                                       <img key={i} src={avatar} className="w-6 h-6 rounded-full border border-zinc-900" alt="Team" />
                                    )) : (
                                       <div className="w-6 h-6 rounded-full bg-zinc-800 flex items-center justify-center border border-zinc-900 text-[8px] text-zinc-500">ME</div>
                                    )}
                                    <button onClick={() => setShareProject(project)} className="w-6 h-6 rounded-full bg-zinc-800 flex items-center justify-center border border-zinc-900 text-zinc-400 hover:text-white hover:bg-zinc-700 text-[10px]">+</button>
                                 </div>
                                 <div className="flex gap-1">
                                    {/* Simple Status Mover for Prototype */}
