import React, { useState, useEffect } from 'react';
import { generateOutreachCampaign } from '../services/gemini';
import { OutreachResult } from '../types';
import { Loader2, Send, Linkedin, Youtube, Facebook, Instagram, Search, Copy, Check, Info, ExternalLink, History, Clock, ChevronRight } from 'lucide-react';

interface SavedCampaign {
  id: string;
  timestamp: number;
  platform: string;
  goal: string;
  audience: string;
  result: OutreachResult;
}

export const OutreachHub: React.FC = () => {
  const [platform, setPlatform] = useState('LinkedIn');
  const [goal, setGoal] = useState('');
  const [audience, setAudience] = useState('');
  const [campaign, setCampaign] = useState<OutreachResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // History State
  const [history, setHistory] = useState<SavedCampaign[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('ranktica_outreach_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) { console.error("Failed to load history", e); }
    }
  }, []);

  const saveToHistory = (result: OutreachResult, p: string, g: string, a: string) => {
    const newItem: SavedCampaign = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      platform: p,
      goal: g,
      audience: a,
      result
    };
    const newHistory = [newItem, ...history].slice(0, 50); // Keep last 50
    setHistory(newHistory);
    localStorage.setItem('ranktica_outreach_history', JSON.stringify(newHistory));
  };

  const loadFromHistory = (item: SavedCampaign) => {
    setPlatform(item.platform);
    setGoal(item.goal);
    setAudience(item.audience);
    setCampaign(item.result);
    setShowHistory(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!goal || !audience) return;
    setLoading(true);
    try {
      const result = await generateOutreachCampaign(platform, goal, audience);
      setCampaign(result);
      saveToHistory(result, platform, goal, audience);
    } catch (e) {
      console.error(e);
      alert("Failed to generate outreach campaign.");
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  const executeSearch = (plat: string, query: string) => {
    let url = '';
    // Clean query slightly
    const q = encodeURIComponent(query.replace(/^["']|["']$/g, '').replace(/Booleans?:?/i, '').trim());

    switch(plat.toLowerCase()) {
      case 'linkedin': url = `https://www.linkedin.com/search/results/people/?keywords=${q}`; break;
      case 'youtube': url = `https://www.youtube.com/results?search_query=${q}`; break;
      case 'facebook': url = `https://www.facebook.com/search/top?q=${q}`; break;
      case 'instagram': url = `https://www.instagram.com/explore/tags/${q.replace(/^#/, '')}/`; break;
    }
    if(url) window.open(url, '_blank');
  };

  const getPlatformIcon = (p: string) => {
    switch (p) {
      case 'LinkedIn': return <Linkedin className="text-blue-500" />;
      case 'YouTube': return <Youtube className="text-red-500" />;
      case 'Facebook': return <Facebook className="text-blue-600" />;
      case 'Instagram': return <Instagram className="text-pink-500" />;
      default: return <Send />;
    }
  };

  return (
    <div className="max-w-7xl mx-auto h-[calc(100vh-6rem)] flex gap-6 animate-fade-in pb-4">

      {/* Sidebar / History Panel */}
      <div className={`fixed inset-y-0 left-0 z-40 w-80 bg-[#0f0f12] border-r border-zinc-800 transform transition-transform duration-300 md:relative md:transform-none md:w-80 md:flex flex-col ${showHistory ? 'translate-x-0' : '-translate-x-full md:translate-x-0'} hidden md:flex`}>
         <div className="p-4 border-b border-zinc-800 bg-[#0f0f12]">
            <h3 className="text-lg font-bold text-white flex items-center gap-2">
               <History size={20} /> History
            </h3>
         </div>
         <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {history.length === 0 ? (
               <div className="text-center text-zinc-500 py-8 text-sm">No saved campaigns yet.</div>
            ) : (
               history.map(item => (
                  <button 
                     key={item.id}
                     onClick={() => loadFromHistory(item)}
                     className="w-full text-left bg-zinc-900 border border-zinc-800 hover:border-blue-500/50 p-3 rounded-xl transition-all group"
                  >
                     <div className="flex justify-between items-start mb-1">
                        <span className="text-xs font-bold text-zinc-400 uppercase">{item.platform}</span>
                        <span className="text-[10px] text-zinc-600">{new Date(item.timestamp).toLocaleDateString()}</span>
                     </div>
                     <p className="text-sm text-white font-medium truncate mb-1">{item.audience}</p>
                     <p className="text-xs text-zinc-500 truncate">{item.goal}</p>
                  </button>
               ))
            )}
         </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="text-center space-y-4 py-4 shrink-0">
          <h2 className="text-3xl font-bold text-white">Outreach Hub</h2>
          <p className="text-zinc-400">Find leads and start conversations that convert.</p>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 space-y-6">
          {/* Input Section */}
          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
            <form onSubmit={handleGenerate} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Platform</label>
                  <div className="grid grid-cols-4 gap-2">
                    {['LinkedIn', 'YouTube', 'Facebook', 'Instagram'].map(p => (
                      <button
                        key={p}
                        type="button"
                        onClick={() => setPlatform(p)}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border transition-all ${
                          platform === p 
                          ? 'bg-zinc-800 border-blue-500 text-white' 
                          : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:bg-zinc-800'
                        }`}
                      >
                        {getPlatformIcon(p)}
                        <span className="text-xs mt-1 font-medium">{p}</span>
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Target Audience</label>
                  <input
                    value={audience}
                    onChange={e => setAudience(e.target.value)}
                    placeholder="e.g. SaaS Founders, Tech Reviewers, Fitness Coaches"
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-blue-500/50 outline-none"
                  />
                </div>
              </div>

              <div className="space-y-4 flex flex-col">
                <div className="flex-1">
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Campaign Goal</label>
                  <textarea
                    value={goal}
                    onChange={e => setGoal(e.target.value)}
                    placeholder="e.g. I want to secure a sponsorship for my channel. Or: I want to collaborate on a video."
                    className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-blue-500/50 outline-none resize-none"
                  />
                </div>

                <button
                  type="submit"
                  disabled={loading || !goal || !audience}
                  className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-600/20 flex items-center justify-center gap-2"
                >
                  {loading ? <Loader2 className="animate-spin" /> : 'Generate Campaign'}
                </button>
              </div>
            </form>
          </div>

          {/* Results */}
          {campaign && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pb-8">
              {/* Strategy Column */}
              <div className="space-y-6">
                <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><Search size={18} /> Finding Leads</h3>
                  <div className="space-y-3">
                    {campaign.searchStrategy.map((strat, i) => (
                      <div key={i} className="bg-zinc-950 p-3 rounded-lg border border-zinc-800/50">
                        <div className="flex justify-between items-center gap-2 mb-2">
                           <span className="text-xs text-zinc-500 font-bold uppercase">Strategy {i+1}</span>
                           <div className="flex gap-1">
                              <button onClick={() => executeSearch(campaign.platform, strat)} className="text-blue-400 hover:text-white p-1" title="Execute Search">
                                <ExternalLink size={14} />
                              </button>
                              <button onClick={() => copyToClipboard(strat, 100+i)} className="text-zinc-500 hover:text-white p-1" title="Copy">
                                {copiedIndex === 100+i ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                              </button>
                           </div>
                        </div>
                        <code className="text-sm text-blue-300 break-words block bg-black/30 p-2 rounded border border-zinc-800">
                          {strat}
                        </code>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><Info size={18} /> Platform Tips</h3>
                  <ul className="space-y-2">
                    {campaign.dosAndDonts.map((tip, i) => (
                      <li key={i} className="text-sm text-zinc-300 flex gap-2">
                        <span className="text-blue-500">•</span> {tip}
                      </li>
                    ))}
                  </ul>
                </div>
              </div>

              {/* Templates Column */}
              <div className="lg:col-span-2 space-y-4">
                <h3 className="text-xl font-bold text-white">Message Sequence</h3>
                {campaign.templates.map((template, idx) => (
                  <div key={idx} className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 hover:border-blue-500/30 transition-colors">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className="text-xs font-bold text-blue-500 uppercase tracking-wider bg-blue-500/10 px-2 py-1 rounded">{template.stage}</span>
                        </div>
                        <button 
                          onClick={() => copyToClipboard(template.subject ? `Subject: ${template.subject}\n\n${template.body}` : template.body, idx)}
                          className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
                        >
                          {copiedIndex === idx ? <><Check size={14} className="text-green-500"/> Copied</> : <><Copy size={14}/> Copy</>}
                        </button>
                      </div>

                      {template.subject && (
                        <div className="mb-4 pb-4 border-b border-zinc-800">
                          <span className="text-zinc-500 text-xs font-bold uppercase block mb-1">Subject Line</span>
                          <p className="text-white font-medium">{template.subject}</p>
                        </div>
                      )}

                      <div className="mb-4">
                        <span className="text-zinc-500 text-xs font-bold uppercase block mb-2">Message Body</span>
                        <div className="bg-zinc-950 p-4 rounded-xl border border-zinc-800/50 whitespace-pre-wrap text-zinc-300 leading-relaxed">
                          {template.body}
                        </div>
                      </div>

                      <div className="bg-blue-500/5 p-3 rounded-lg border border-blue-500/10">
                        <p className="text-xs text-blue-300 italic">💡 Strategy: {template.explanation}</p>
                      </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

