  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);
  const [voiceoverText, setVoiceoverText] = useState('');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);

  // Refs for playback
  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const previewAudioRef = useRef<HTMLAudioElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);
  const requestRef = useRef<number>(0);
  const startTimeRef = useRef<number>(0);

  // --- GENERATOR LOGIC ---

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 4000);
    } else {
      setLoadingMsgIndex(0);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    setGeneratedVideoUrl(null);
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      alert("Video generation failed. Ensure you have selected a paid API key via the dialog.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `Veo Generation ${timeline.length + 1}`);
      setActiveTab('edit');
    }
  };

  // --- EDITOR LOGIC ---

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;
      const newClip: TimelineClip = {
        id: Date.now().toString(),
        type: 'video',
        url,
        name,
        duration,
        trimStart: 0,
        trimEnd: duration,
        timelineOffset: calculateNextOffset()
      };
      setTimeline(prev => [...prev, newClip]);
      recalculateTotalDuration([...timeline, newClip]);
    };
  };

  const handleEditorUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addVideoToTimeline(url, file.name);
    }
  };

  const calculateNextOffset = () => {
    if (timeline.length === 0) return 0;
    const videoClips = timeline.filter(c => c.type === 'video');
    if (videoClips.length === 0) return 0;
    const last = videoClips[videoClips.length - 1];
    return last.timelineOffset + (last.trimEnd - last.trimStart);
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const end = c.timelineOffset + (c.trimEnd - c.trimStart);
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const handleGenerateVoiceover = async () => {
    if (!voiceoverText.trim()) return;
    setIsGeneratingVoice(true);
    try {
      const base64Audio = await generateSpeech(voiceoverText);
      if (base64Audio) {
        const binaryString = atob(base64Audio);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
        const blob = new Blob([bytes], { type: 'audio/mp3' });
        const url = URL.createObjectURL(blob);

        const tempAudio = document.createElement('audio');
        tempAudio.src = url;
        tempAudio.onloadedmetadata = () => {
           const duration = tempAudio.duration || 5; 
           const newClip: TimelineClip = {
              id: Date.now().toString(),
              type: 'audio',
              url,
              name: `Voiceover: ${voiceoverText.substring(0, 10)}...`,
              duration,
              trimStart: 0,
              trimEnd: duration,
              timelineOffset: currentTime
           };
           const newTimeline = [...timeline, newClip];
           setTimeline(newTimeline);
           recalculateTotalDuration(newTimeline);
           setVoiceoverText('');
        };
      }
    } catch (e) {
      console.error(e);
      alert("Voiceover generation failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const updateClip = (id: string, updates: Partial<TimelineClip>) => {
    const updated = timeline.map(c => c.id === id ? { ...c, ...updates } : c);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  const removeClip = (id: string) => {
    const updated = timeline.filter(c => c.id !== id);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  // --- PLAYBACK ENGINE ---

  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };

  const seek = (time: number) => {
    setCurrentTime(time);
    syncPlayer(time);
  };

  const syncPlayer = (time: number) => {
    const videoClip = timeline.find(c => c.type === 'video' && time >= c.timelineOffset && time < (c.timelineOffset + (c.trimEnd - c.trimStart)));

    if (previewVideoRef.current) {
       if (videoClip) {
          const vidUrl = videoClip.url;
          if (!previewVideoRef.current.src.includes(vidUrl)) {
             previewVideoRef.current.src = vidUrl;
          }
          const internalTime = videoClip.trimStart + (time - videoClip.timelineOffset);
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.5) {
            previewVideoRef.current.currentTime = internalTime;
          }
          if (isPlaying) {
             previewVideoRef.current.play().catch(() => {});
          } else {
             previewVideoRef.current.pause();
          }
          previewVideoRef.current.style.opacity = '1';
       } else {
          previewVideoRef.current.pause();
          previewVideoRef.current.style.opacity = '0';
       }
    }

    const audioClip = timeline.find(c => c.type === 'audio' && time >= c.timelineOffset && time < (c.timelineOffset + (c.trimEnd - c.trimStart)));

    if (previewAudioRef.current) {
        if (audioClip) {
           if (!previewAudioRef.current.src.includes(audioClip.url)) {
              previewAudioRef.current.src = audioClip.url;
           }
           const internalTime = audioClip.trimStart + (time - audioClip.timelineOffset);
           if (Math.abs(previewAudioRef.current.currentTime - internalTime) > 0.5) {
             previewAudioRef.current.currentTime = internalTime;
           }
           if (isPlaying) previewAudioRef.current.play().catch(() => {});
           else previewAudioRef.current.pause();
        } else {
           previewAudioRef.current.pause();
        }
    }
  };

  useEffect(() => {
    let animationFrameId: number;
    const animate = () => {
      if (isPlaying) {
        setCurrentTime(prev => {
          const next = prev + 0.033;
          if (next >= totalDuration && totalDuration > 0) {
            setIsPlaying(false);
            return 0;
          }
          syncPlayer(next);
          return next;
        });
      }
      animationFrameId = requestAnimationFrame(animate);
    };
    if (isPlaying) {
      animationFrameId = requestAnimationFrame(animate);
    } else {
      syncPlayer(currentTime);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration, timeline]);


  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in">
       <header className="flex items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-4">
          <div>
            <h2 className="text-2xl font-bold text-white">Video Studio</h2>
            <p className="text-zinc-400 text-sm">Powered by Veo & Gemini 3 Pro</p>
          </div>
          <div className="flex bg-zinc-900 rounded-lg p-1 border border-zinc-800">
             <button 
               onClick={() => setActiveTab('create')}
               className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow' : 'text-zinc-500 hover:text-white'}`}
             >
               Create (Veo)
             </button>
             <button 
               onClick={() => setActiveTab('edit')}
               className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow' : 'text-zinc-500 hover:text-white'}`}
             >
               Edit (Timeline)
             </button>
          </div>
       </header>

       {activeTab === 'create' && (
         <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
            <div className="w-full md:w-1/3 flex flex-col gap-4">
              <form onSubmit={handleGenerate} className="bg-zinc-900 p-6 rounded-2xl border border-zinc-800 space-y-4">
                <div className="mb-4">
                    <label className="text-xs font-medium text-zinc-500 mb-2 block">Start Image (Optional)</label>
                    <div 
                      onClick={() => fileInputRef.current?.click()}
                      className="w-full h-32 border-2 border-dashed border-zinc-700 hover:border-green-500 rounded-xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950 transition-colors relative group"
                    >
                      {startImage ? (
                        <>
                            <img src={startImage} alt="Upload" className="h-full w-full object-cover rounded-xl opacity-60" />
                            <div className="absolute inset-0 flex items-center justify-center">
                                <span className="bg-black/70 px-2 py-1 rounded text-xs">Change Image</span>
                            </div>
                        </>
                      ) : (
                        <div className="text-zinc-500 flex flex-col items-center gap-2">
                          <Upload size={24} />
                          <span className="text-xs">Upload to Animate</span>
                        </div>
                      )}
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Video Prompt</label>
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="e.g. A neon hologram of a cat driving at top speed"
                    className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-green-500/50 outline-none transition-all resize-none text-white text-sm"
                  />
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Aspect Ratio</label>
                  <select 
                    value={aspectRatio}
                    onChange={(e) => setAspectRatio(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white"
                  >
                    <option value="16:9">16:9 (Landscape)</option>
                    <option value="9:16">9:16 (Portrait / Shorts)</option>
                  </select>
                </div>

                <button
                  type="submit"
                  disabled={isGenerating || (!prompt && !startImage)}
                  className="w-full bg-green-600 hover:bg-green-500 disabled:opacity-50 text-white py-3 rounded-xl font-semibold transition-all shadow-[0_0_20px_rgba(22,163,74,0.3)] flex items-center justify-center gap-2"
                >
                  {isGenerating ? <Loader2 className="animate-spin" /> : <><PlayCircle size={18} /> Generate Video</>}
                </button>
              </form>
            </div>

            <div className="flex-1 bg-zinc-950 rounded-2xl border border-zinc-800 flex items-center justify-center relative overflow-hidden group">
              {isGenerating ? (
                <div className="flex flex-col items-center gap-4 text-green-500">
                    <Loader2 className="animate-spin w-12 h-12" />
                    <span className="text-sm text-zinc-400 animate-pulse transition-all duration-500">
                      {LOADING_MESSAGES[loadingMsgIndex]}
                    </span>
                </div>
              ) : generatedVideoUrl ? (
                <>
                  <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain" />
                  <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={sendToEditor}
                        className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-full font-medium text-sm flex items-center gap-2 backdrop-blur-sm transition-colors"
                      >
                         <Scissors size={16} /> Edit
                      </button>
                      <a 
                        href={generatedVideoUrl} 
                        download={`ranktica_video_${Date.now()}.mp4`}
                        className="bg-black/70 hover:bg-black text-white px-4 py-2 rounded-full font-medium text-sm flex items-center gap-2 backdrop-blur-sm transition-colors"
                      >
                        <Download size={16} /> Download
                      </a>
                  </div>
                </>
              ) : (
                <div className="text-zinc-700 flex flex-col items-center gap-4">
                    <VideoIcon size={64} className="opacity-50" />
                    <p>Generated video will appear here</p>
                </div>
              )}
            </div>
         </div>
       )}

       {activeTab === 'edit' && (
         <div className="flex-1 flex flex-col gap-4 overflow-hidden">
            <div className="flex-1 bg-black rounded-xl relative flex items-center justify-center overflow-hidden border border-zinc-800">
               <video ref={previewVideoRef} className="max-h-full max-w-full" />
               <audio ref={previewAudioRef} />
               {timeline.length === 0 && (
                 <div className="text-zinc-600 flex flex-col items-center gap-2">
                    <Layers size={48} />
                    <p>Timeline is empty. Add clips to start editing.</p>
                 </div>
               )}
            </div>

            <div className="h-[45%] bg-zinc-900 border border-zinc-800 rounded-xl flex flex-col overflow-hidden">
               <div className="h-12 border-b border-zinc-800 flex items-center justify-between px-4 bg-zinc-950">
                  <div className="flex items-center gap-2">
                     <button onClick={() => seek(0)} className="p-2 text-zinc-400 hover:text-white"><SkipBack size={16} /></button>
                     <button onClick={togglePlay} className="p-2 text-white hover:text-green-400">
                        {isPlaying ? <PauseCircle size={24} /> : <PlayCircle size={24} />}
                     </button>
                     <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-400 hover:text-white"><SkipForward size={16} /></button>
                     <span className="text-xs font-mono text-zinc-500 ml-2">
                        {currentTime.toFixed(1)}s / {totalDuration.toFixed(1)}s
                     </span>
                  </div>

                  <div className="flex items-center gap-3">
                     <button 
                       onClick={() => editorFileInputRef.current?.click()}
                       className="text-xs flex items-center gap-1 bg-zinc-800 hover:bg-zinc-700 text-white px-3 py-1.5 rounded-md border border-zinc-700"
                     >
                       <Plus size={14} /> Add Video
                     </button>
                     <input type="file" ref={editorFileInputRef} onChange={handleEditorUpload} className="hidden" accept="video/*" />
                     <div className="flex items-center gap-2 bg-zinc-800 rounded-md p-0.5 border border-zinc-700">
                        <input value={voiceoverText} onChange={e => setVoiceoverText(e.target.value)} placeholder="AI Voiceover text..." className="bg-transparent border-none outline-none text-xs text-white px-2 w-48" />
                        <button onClick={handleGenerateVoiceover} disabled={isGeneratingVoice || !voiceoverText} className="bg-purple-600 hover:bg-purple-500 text-white p-1.5 rounded disabled:opacity-50">
                           {isGeneratingVoice ? <Loader2 size={14} className="animate-spin" /> : <Mic size={14} />}
                        </button>
                     </div>
                  </div>
               </div>

               <div className="flex-1 overflow-y-auto p-4 space-y-2 bg-zinc-900/50">
                  {timeline.length === 0 && <div className="text-center text-zinc-600 text-sm py-8">Drag and drop or use "Add Video" to start.</div>}
                  {timeline.map((clip) => (
                    <div key={clip.id} className="group relative bg-zinc-950 border border-zinc-800 rounded-lg p-3 flex gap-4 items-center hover:border-zinc-600 transition-colors">
                       <div className={`p-2 rounded-lg ${clip.type === 'video' ? 'bg-blue-500/10 text-blue-400' : 'bg-purple-500/10 text-purple-400'}`}>
                          {clip.type === 'video' ? <Film size={18} /> : <Volume2 size={18} />}
                       </div>
                       <div className="flex-1 min-w-0">
                          <div className="flex justify-between mb-1">
                             <span className="text-sm font-medium text-zinc-300 truncate">{clip.name}</span>
                             <button onClick={() => removeClip(clip.id)} className="text-zinc-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                <Trash2 size={14} />
                             </button>
                          </div>
                          <div className="flex items-center gap-4 text-xs text-zinc-500">
                             <div className="flex items-center gap-2">
                                <span>Start:</span>
                                <input type="number" value={clip.trimStart} step={0.1} max={clip.trimEnd} min={0} onChange={(e) => updateClip(clip.id, { trimStart: parseFloat(e.target.value) })} className="w-16 bg-zinc-900 border border-zinc-700 rounded px-1 text-white outline-none" />
                             </div>
                             <div className="flex items-center gap-2">
                                <span>End:</span>
                                <input type="number" value={clip.trimEnd} step={0.1} max={clip.duration} min={clip.trimStart} onChange={(e) => updateClip(clip.id, { trimEnd: parseFloat(e.target.value) })} className="w-16 bg-zinc-900 border border-zinc-700 rounded px-1 text-white outline-none" />
                             </div>
                             <span>Duration: {(clip.trimEnd - clip.trimStart).toFixed(1)}s</span>
                             <span className={`ml-auto px-2 rounded ${clip.type === 'video' ? 'text-blue-400 bg-blue-500/10' : 'text-purple-400 bg-purple-500/10'}`}>Offset: {clip.timelineOffset.toFixed(1)}s</span>
                          </div>
                          <div className="mt-2 h-1.5 w-full bg-zinc-800 rounded-full overflow-hidden relative">
                             <div className={`absolute top-0 bottom-0 ${clip.type === 'video' ? 'bg-blue-600' : 'bg-purple-600'}`} style={{ left: `${(clip.trimStart / clip.duration) * 100}%`, right: `${100 - (clip.trimEnd / clip.duration) * 100}%` }}></div>
                          </div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
         </div>
       )}
    </div>
  );
};

