function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

import React, { useState, useRef, useEffect } from 'react';
import { generateVideo, generateSpeech } from '../services/gemini';
import { Loader2, Video as VideoIcon, Upload, PlayCircle, Download, Scissors, Mic, Layers, Plus, Trash2, PauseCircle, SkipBack, SkipForward, Wand2, Volume2, Film, Settings2 } from 'lucide-react';

const LOADING_MESSAGES = [
  "Initializing Veo creative engine...",
  "Analyzing prompt and visual styles...",
  "Rendering frames (this takes a moment)...",
  "Applying lighting and physics...",
  "Polishing final output...",
  "Almost ready..."
];

