               )}
            </div>

            <div className="h-[45%] bg-zinc-900 border border-zinc-800 rounded-xl flex flex-col overflow-hidden">
               <div className="h-12 border-b border-zinc-800 flex items-center justify-between px-4 bg-zinc-950">
                  <div className="flex items-center gap-2">
                     <button onClick={() => seek(0)} className="p-2 text-zinc-400 hover:text-white"><SkipBack size={16} /></button>
                     <button onClick={togglePlay} className="p-2 text-white hover:text-green-400">
                        {isPlaying ? <PauseCircle size={24} /> : <PlayCircle size={24} />}
                     </button>
                     <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-400 hover:text-white"><SkipForward size={16} /></button>
                     <span className="text-xs font-mono text-zinc-500 ml-2">
                        {currentTime.toFixed(1)}s / {totalDuration.toFixed(1)}s
                     </span>
                  </div>

                  <div className="flex items-center gap-3">
                     <button 
                       onClick={() => editorFileInputRef.current?.click()}
                       className="text-xs flex items-center gap-1 bg-zinc-800 hover:bg-zinc-700 text-white px-3 py-1.5 rounded-md border border-zinc-700"
                     >
                       <Plus size={14} /> Add Video
                     </button>
                     <input type="file" ref={editorFileInputRef} onChange={handleEditorUpload} className="hidden" accept="video/*" />

                     <div className="flex items-center gap-2 bg-zinc-800 rounded-md p-0.5 border border-zinc-700">
                        <select 
                          value={selectedVoice} 
                          onChange={e => setSelectedVoice(e.target.value)}
                          className="bg-transparent border-none outline-none text-xs text-zinc-300 px-2 py-1 cursor-pointer hover:text-white"
                        >
                          {VOICE_STYLES.map(v => <option key={v.id} value={v.id} className="bg-zinc-900">{v.label}</option>)}
                        </select>
                        <div className="w-px h-4 bg-zinc-700 mx-1"></div>
                        <input 
                          value={voiceoverText} 
                          onChange={e => setVoiceoverText(e.target.value)} 
                          placeholder="AI Voiceover text..." 
                          className="bg-transparent border-none outline-none text-xs text-white px-2 w-48" 
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && voiceoverText) handleGenerateVoiceover();
                          }}
