// --- Research / Chat ---
export const researchChat = async (
  history: any[], 
  message: string, 
  image?: string,
  useThinking: boolean = false,
  tools: { search: boolean; maps: boolean } = { search: false, maps: false }
) => {
  const ai = getAiClient();

  const configuredTools: any[] = [];
  if (tools.search) configuredTools.push({ googleSearch: {} });
  if (tools.maps) configuredTools.push({ googleMaps: {} });

  const config: any = {
    systemInstruction: SYSTEM_INSTRUCTIONS.RESEARCH,
    tools: configuredTools.length > 0 ? configuredTools : undefined
  };

  if (useThinking) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const model = MODEL_NAMES.TEXT_SMART; 

  const parts: any[] = [];
  if (image) {
    const cleanBase64 = image.replace(/^data:image\/\w+;base64,/, "");
    parts.push({
      inlineData: {
        data: cleanBase64,
        mimeType: 'image/png' 
      }
    });
  }
  parts.push({ text: message });

  const response = await ai.models.generateContent({
    model: model,
    contents: { parts },
    config: config
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => {
    if (chunk.web) return { title: chunk.web.title, uri: chunk.web.uri };
    if (chunk.maps) return { title: chunk.maps.title || "Maps Location", uri: chunk.maps.uri || "" }; 
    return null;
  }).filter(Boolean) || [];

  return {
    text: response.text || "No response generated.",
    sources
  };
};

