            currentSolutions: { type: Type.STRING },
            opportunityScore: { type: Type.NUMBER }
          }
        }
      }
    }
  });

  const text = response.text;
  if (!text) return [];
  try {
    const res = JSON.parse(text) as NicheGap[];
    return Array.isArray(res) ? res : [];
  } catch (e) {
    console.error(e);
    return [];
  }
};

export const forecastTrends = async (topic: string): Promise<TrendForecast> => {
  const ai = getAiClient();
  const prompt = `Forecast the 5-year trend for: "${topic}".`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.MARKET_STRATEGY,
      thinkingConfig: { thinkingBudget: 4096 }, // Use thinking for prediction
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          topic: { type: Type.STRING },
          forecast: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                year: { type: Type.NUMBER },
                interest: { type: Type.NUMBER },
                keyDriver: { type: Type.STRING }
              }
            }
          },
          summary: { type: Type.STRING }
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Forecast failed");
  const res = JSON.parse(text) as TrendForecast;
  return {
    ...res,
    forecast: res.forecast || []
  };
};

function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

