                      )}
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Video Prompt</label>
                  <textarea
                    value={prompt}
