                          {clip.type === 'video' ? <Film size={24} /> : <Mic size={24} />}
                       </div>

                       <div className="flex-1 min-w-0 space-y-4">
                          <div className="flex justify-between items-start">
                             <div className="min-w-0">
                                <h4 className="text-sm font-bold text-white truncate">{clip.name}</h4>
                                <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-widest mt-0.5">{clip.type} Clip</p>
                             </div>
                             <div className="flex gap-2">
                                <button 
                                  onClick={() => handleSmartTrim(clip.id)}
                                  className="p-2 text-zinc-500 hover:text-yellow-500 transition-colors bg-zinc-950 rounded-lg border border-zinc-800"
                                  title="AI Smart Trim"
                                >
                                   <Zap size={14} />
                                </button>
                                <button 
                                  onClick={() => removeClip(clip.id)} 
                                  className="p-2 text-zinc-500 hover:text-red-500 transition-colors bg-zinc-950 rounded-lg border border-zinc-800"
                                  title="Remove Clip"
                                >
                                   <Trash2 size={14} />
                                </button>
                             </div>
                          </div>

                          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 items-end">
                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Trim Start</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <Scissors size={10} className="text-zinc-500" />
                                   <input type="number" value={clip.trimStart} step={0.1} max={clip.trimEnd} min={0} onChange={(e) => updateClip(clip.id, { trimStart: parseFloat(e.target.value) })} className="bg-transparent border-none outline-none text-xs text-white w-full" />
                                </div>
                             </div>

                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Trim End</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <Scissors size={10} className="text-zinc-500" />
                                   <input type="number" value={clip.trimEnd} step={0.1} max={clip.duration} min={clip.trimStart} onChange={(e) => updateClip(clip.id, { trimEnd: parseFloat(e.target.value) })} className="bg-transparent border-none outline-none text-xs text-white w-full" />
                                </div>
                             </div>

                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Playback Speed</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <FastForward size={10} className="text-zinc-500" />
                                   <select 
                                     value={clip.playbackSpeed} 
                                     onChange={(e) => updateClip(clip.id, { playbackSpeed: parseFloat(e.target.value) })}
                                     className="bg-transparent border-none outline-none text-xs text-white w-full cursor-pointer"
                                   >
                                      {SPEED_OPTIONS.map(s => <option key={s} value={s} className="bg-zinc-950">{s}x</option>)}
                                   </select>
                                </div>
                             </div>

                             <div className="flex flex-col justify-end text-right">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Duration</span>
                                <p className="text-xs font-mono text-zinc-300">
                                   {((clip.trimEnd - clip.trimStart) / clip.playbackSpeed).toFixed(2)}s
                                </p>
                             </div>
                          </div>

                          <div className="space-y-1.5">
                             <div className="flex justify-between text-[10px] font-bold text-zinc-600 uppercase">
                                <span>Timeline Track</span>
                                <span className="text-zinc-400">Starts @ {clip.timelineOffset.toFixed(2)}s</span>
                             </div>
                             <div className="h-2 w-full bg-zinc-950 rounded-full overflow-hidden relative border border-zinc-800">
                                <div 
                                  className={`absolute top-0 bottom-0 ${clip.type === 'video' ? 'bg-blue-600' : 'bg-red-600'} transition-all duration-300`} 
                                  style={{ 
                                    left: `${(clip.trimStart / clip.duration) * 100}%`, 
                                    right: `${100 - (clip.trimEnd / clip.duration) * 100}%` 
                                  }}
                                ></div>
                             </div>
                          </div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
         </div>
       )}
    </div>
  );
};

