// --- Images (Standard & Pro) ---
export const generateThumbnail = async (
  prompt: string, 
  style: string = 'Photorealistic', 
  usePro: boolean = false,
  aspectRatio: string = '1:1',
  imageSize: string = '1K'
): Promise<string | null> => {
  const ai = getAiClient();
  const enhancedPrompt = `A high-quality, eye-catching YouTube thumbnail for: ${prompt}. Art Style: ${style}. Vibrant colors, high contrast. No text.`;

  const model = usePro ? MODEL_NAMES.IMAGE_PRO : MODEL_NAMES.IMAGE_FAST;

  const config: any = {};
  if (usePro) {
    config.imageConfig = { aspectRatio, imageSize };
  }

  const response = await ai.models.generateContent({
    model: model,
    contents: enhancedPrompt,
    config: config
  });

  const parts = response.candidates?.[0]?.content?.parts;
  if (parts) {
    for (const part of parts) {
      if (part.inlineData && part.inlineData.data) {
         return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }
  return null;
};

export const editImage = async (base64Image: string, prompt: string): Promise<string | null> => {
  const ai = getAiClient();
  const base64Data = base64Image.replace(/^data:image\/\w+;base64,/, "");

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.IMAGE_FAST,
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Data,
            mimeType: 'image/png' 
          }
        },
        { text: prompt }
      ]
    }
  });

  const parts = response.candidates?.[0]?.content?.parts;
  if (parts) {
    for (const part of parts) {
      if (part.inlineData && part.inlineData.data) {
         return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }
  return null;
};

