export const generateMarketingSchedule = async (
  topic: string, 
  platforms: string[] = ['twitter', 'linkedin', 'instagram', 'facebook']
): Promise<SocialPost[]> => {
  const ai = getAiClient();
  const platformString = platforms.map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(', ');
  const prompt = `Create a 7-day marketing schedule for the YouTube video topic: "${topic}". Include posts for ${platformString}.`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.MARKETING,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.NUMBER },
            platform: { type: Type.STRING, enum: ["twitter", "linkedin", "instagram", "facebook"] },
            content: { type: Type.STRING },
            hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
            time: { type: Type.STRING },
            visualPrompt: { type: Type.STRING }
          },
          required: ["day", "platform", "content", "time", "visualPrompt"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) return [];
  try {
    const posts = JSON.parse(text) as SocialPost[];
    // Ensure all posts have hashtags array
    return posts.map(p => ({
      ...p,
      hashtags: p.hashtags || [],
      status: 'pending'
    }));
  } catch (e) {
    console.error("Failed to parse JSON", e);
    return [];
  }
};

