export const generatePersona = async (niche: string, gender: string = ''): Promise<CustomerPersona> => {
  const ai = getAiClient();
  let prompt = `Create a detailed customer persona for the niche: "${niche}".`;
  if (gender) {
    prompt += ` The persona must be ${gender}.`;
  }

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.MARKET_STRATEGY,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          gender: { type: Type.STRING, enum: ['Male', 'Female', 'Other'] },
          ageRange: { type: Type.STRING },
          occupation: { type: Type.STRING },
          quote: { type: Type.STRING },
          demographics: {
            type: Type.OBJECT,
            properties: {
              location: { type: Type.STRING },
              incomeLevel: { type: Type.STRING },
              education: { type: Type.STRING },
              familyStatus: { type: Type.STRING }
            }
          },
          psychographics: {
            type: Type.OBJECT,
            properties: {
              goals: { type: Type.ARRAY, items: { type: Type.STRING } },
              painPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
              values: { type: Type.ARRAY, items: { type: Type.STRING } },
              hobbies: { type: Type.ARRAY, items: { type: Type.STRING } },
              fears: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          buyingBehavior: { type: Type.STRING },
          contentPreferences: { type: Type.ARRAY, items: { type: Type.STRING } },
          dailyRoutine: { type: Type.STRING },
          favoriteBrands: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Persona generation failed");
  const res = JSON.parse(text) as CustomerPersona;

  // Sanitize
  return {
    ...res,
    demographics: res.demographics || { location: 'Unknown', incomeLevel: 'Unknown', education: 'Unknown', familyStatus: 'Unknown' },
    psychographics: {
      goals: res.psychographics?.goals || [],
      painPoints: res.psychographics?.painPoints || [],
      values: res.psychographics?.values || [],
      hobbies: res.psychographics?.hobbies || [],
      fears: res.psychographics?.fears || []
    },
    contentPreferences: res.contentPreferences || [],
    favoriteBrands: res.favoriteBrands || []
  };
};

