export const forecastTrends = async (topic: string): Promise<TrendForecast> => {
  const ai = getAiClient();
  const prompt = `Forecast the 5-year trend for: "${topic}".`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.MARKET_STRATEGY,
      thinkingConfig: { thinkingBudget: 4096 }, // Use thinking for prediction
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          topic: { type: Type.STRING },
          forecast: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                year: { type: Type.NUMBER },
                interest: { type: Type.NUMBER },
                keyDriver: { type: Type.STRING }
              }
            }
          },
          summary: { type: Type.STRING }
        }
      }
