    const updatedSchedule = [...schedule];
    updatedSchedule[index].status = 'scheduled';
    setSchedule(updatedSchedule);
  };

  const copyPost = (content: string) => {
    navigator.clipboard.writeText(content);
    alert("Post content copied!");
  };

