  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  // Voiceover Modal State
  const [isVoiceoverModalOpen, setIsVoiceoverModalOpen] = useState(false);
  const [voiceoverText, setVoiceoverText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState('Kore');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [previewAudioUrl, setPreviewAudioUrl] = useState<string | null>(null);

  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);

  // Refs for playback
  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const previewAudioRef = useRef<HTMLAudioElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);

  // --- GENERATOR LOGIC ---

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 4000);
    } else {
      setLoadingMsgIndex(0);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    setGeneratedVideoUrl(null);
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      alert("Video generation failed. Ensure you have selected a paid API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `Veo Generation ${timeline.length + 1}`);
      setActiveTab('edit');
    }
  };

  // --- EDITOR LOGIC ---

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;
      const newClip: TimelineClip = {
        id: Date.now().toString(),
        type: 'video',
        url,
        name,
        duration,
        trimStart: 0,
        trimEnd: duration,
        timelineOffset: calculateNextOffset(),
        playbackSpeed: 1
      };
      const updatedTimeline = [...timeline, newClip];
      setTimeline(updatedTimeline);
      recalculateTotalDuration(updatedTimeline);
    };
  };

  const handleEditorUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addVideoToTimeline(url, file.name);
    }
  };

  const calculateNextOffset = () => {
    if (timeline.length === 0) return 0;
    const last = timeline[timeline.length - 1];
    const clipDuration = (last.trimEnd - last.trimStart) / last.playbackSpeed;
    return last.timelineOffset + clipDuration;
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const clipDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
      const end = c.timelineOffset + clipDuration;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const handleGenerateVoiceoverPreview = async () => {
    if (!voiceoverText.trim()) return;
    setIsGeneratingVoice(true);
    setPreviewAudioUrl(null);
    try {
      const base64Audio = await generateSpeech(voiceoverText, selectedVoice);
      if (base64Audio) {
        const wavBlob = decodeRawPcmToWavBlob(base64Audio);
        const url = URL.createObjectURL(wavBlob);
        setPreviewAudioUrl(url);
      }
    } catch (e) {
      console.error(e);
      alert("Voiceover generation failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const addVoiceoverToTimeline = () => {
    if (!previewAudioUrl) return;

    const tempAudio = document.createElement('audio');
    tempAudio.src = previewAudioUrl;
    tempAudio.onloadedmetadata = () => {
       const duration = tempAudio.duration || 5; 
       const newClip: TimelineClip = {
          id: Date.now().toString(),
          type: 'audio',
          url: previewAudioUrl,
          name: `Voiceover: ${voiceoverText.substring(0, 15)}...`,
          duration,
          trimStart: 0,
          trimEnd: duration,
          timelineOffset: currentTime,
          playbackSpeed: 1
       };
       const newTimeline = [...timeline, newClip];
       setTimeline(newTimeline);
       recalculateTotalDuration(newTimeline);

       // Reset modal
       setVoiceoverText('');
       setPreviewAudioUrl(null);
       setIsVoiceoverModalOpen(false);
    };
  };

  const updateClip = (id: string, updates: Partial<TimelineClip>) => {
    const updated = timeline.map(c => c.id === id ? { ...c, ...updates } : c);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  const removeClip = (id: string) => {
    const updated = timeline.filter(c => c.id !== id);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  const handleSmartTrim = async (clipId: string) => {
    const clip = timeline.find(c => c.id === clipId);
    if (!clip) return;
    const thinking = confirm(`Allow AI to suggest optimal trimming for "${clip.name}"?`);
    if (!thinking) return;

    const suggestedStart = clip.duration * 0.1;
    const suggestedEnd = clip.duration * 0.9;
    updateClip(clipId, { trimStart: suggestedStart, trimEnd: suggestedEnd });
  };

  const handleExport = () => {
    if (timeline.length === 0) return;
    setIsExporting(true);
    setExportProgress(0);
    const interval = setInterval(() => {
      setExportProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => {
             setIsExporting(false);
             alert("Project exported successfully!");
          }, 500);
          return 100;
        }
        return prev + 5;
      });
    }, 200);
  };

  // --- PLAYBACK ENGINE ---

  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };

  const seek = (time: number) => {
    setCurrentTime(Math.max(0, Math.min(time, totalDuration)));
  };

  const syncPlayer = (time: number) => {
    const videoClip = timeline.find(c => {
      const clipEffectiveDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
      return c.type === 'video' && time >= c.timelineOffset && time < (c.timelineOffset + clipEffectiveDuration);
    });

    if (previewVideoRef.current) {
       if (videoClip) {
          if (!previewVideoRef.current.src.includes(videoClip.url)) {
             previewVideoRef.current.src = videoClip.url;
          }
          const timeIntoClip = time - videoClip.timelineOffset;
          const internalTime = videoClip.trimStart + (timeIntoClip * videoClip.playbackSpeed);
          if (previewVideoRef.current.playbackRate !== videoClip.playbackSpeed) {
            previewVideoRef.current.playbackRate = videoClip.playbackSpeed;
          }
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.3) {
            previewVideoRef.current.currentTime = internalTime;
          }
          if (isPlaying) previewVideoRef.current.play().catch(() => {});
          else previewVideoRef.current.pause();
          previewVideoRef.current.style.opacity = '1';
       } else {
          previewVideoRef.current.pause();
          previewVideoRef.current.style.opacity = '0';
       }
    }

    const audioClip = timeline.find(c => {
        const clipEffectiveDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
        return c.type === 'audio' && time >= c.timelineOffset && time < (c.timelineOffset + clipEffectiveDuration);
    });

    if (previewAudioRef.current) {
        if (audioClip) {
           if (!previewAudioRef.current.src.includes(audioClip.url)) {
              previewAudioRef.current.src = audioClip.url;
           }
           const timeIntoClip = time - audioClip.timelineOffset;
           const internalTime = audioClip.trimStart + (timeIntoClip * audioClip.playbackSpeed);
           if (previewAudioRef.current.playbackRate !== audioClip.playbackSpeed) {
              previewAudioRef.current.playbackRate = audioClip.playbackSpeed;
           }
           if (Math.abs(previewAudioRef.current.currentTime - internalTime) > 0.3) {
             previewAudioRef.current.currentTime = internalTime;
           }
           if (isPlaying) previewAudioRef.current.play().catch(() => {});
           else previewAudioRef.current.pause();
        } else {
           previewAudioRef.current.pause();
        }
    }
  };

  useEffect(() => {
    let animationFrameId: number;
    const animate = () => {
      if (isPlaying) {
        setCurrentTime(prev => {
          const next = prev + 0.033;
          if (next >= totalDuration && totalDuration > 0) {
            setIsPlaying(false);
            return 0;
          }
          return next;
        });
      }
      animationFrameId = requestAnimationFrame(animate);
    };
    animationFrameId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    syncPlayer(currentTime);
  }, [currentTime, timeline, isPlaying]);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in">
       <header className="flex items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-4">
          <div>
            <h2 className="text-2xl font-bold text-white">Video Studio</h2>
            <p className="text-zinc-400 text-sm">Professional AI Production Console</p>
          </div>
          <div className="flex gap-4">
            <div className="flex bg-zinc-900 rounded-lg p-1 border border-zinc-800">
              <button 
                onClick={() => setActiveTab('create')}
                className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow' : 'text-zinc-500 hover:text-white'}`}
              >
                Clip Generator
              </button>
              <button 
                onClick={() => setActiveTab('edit')}
                className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow' : 'text-zinc-500 hover:text-white'}`}
              >
                Timeline Editor
              </button>
            </div>

            {activeTab === 'edit' && timeline.length > 0 && (
              <button 
                onClick={handleExport}
                disabled={isExporting}
                className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 shadow-lg shadow-green-600/20 disabled:opacity-50"
              >
                 {isExporting ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />}
                 {isExporting ? `Exporting ${exportProgress}%` : 'Finalize Project'}
              </button>
            )}
          </div>
       </header>

       {activeTab === 'create' && (
         <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
            <div className="w-full md:w-1/3 flex flex-col gap-4">
              <form onSubmit={handleGenerate} className="bg-zinc-900 p-6 rounded-2xl border border-zinc-800 space-y-4">
                <div className="mb-4">
                    <label className="text-[10px] font-bold text-zinc-500 mb-2 block uppercase tracking-widest">Starting Frame</label>
                    <div 
                      onClick={() => fileInputRef.current?.click()}
                      className="w-full h-32 border-2 border-dashed border-zinc-700 hover:border-red-500 rounded-xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950 transition-colors relative group"
                    >
                      {startImage ? (
                        <>
                            <img src={startImage} alt="Upload" className="h-full w-full object-cover rounded-xl opacity-60" />
                            <div className="absolute inset-0 flex items-center justify-center">
                                <span className="bg-black/70 px-2 py-1 rounded text-xs text-white">Replace Image</span>
                            </div>
                        </>
                      ) : (
                        <div className="text-zinc-500 flex flex-col items-center gap-2">
                          <Upload size={24} />
                          <span className="text-[10px] font-bold uppercase">Upload Image</span>
                        </div>
                      )}
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Action Prompt</label>
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe the cinematic action..."
                    className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-xl p-4 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm"
                  />
                </div>

                <div>
                  <label className="text-sm font-medium text-zinc-300 mb-2 block">Aspect Ratio</label>
                  <select 
                    value={aspectRatio}
                    onChange={(e) => setAspectRatio(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl p-4 text-white appearance-none cursor-pointer focus:ring-2 focus:ring-red-500/50"
                  >
                    <option value="16:9">16:9 Landscape</option>
                    <option value="9:16">9:16 Vertical / Shorts</option>
                  </select>
                </div>

                <button
                  type="submit"
                  disabled={isGenerating || (!prompt && !startImage)}
                  className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-4 rounded-xl font-bold transition-all shadow-[0_0_30px_rgba(220,38,38,0.2)] flex items-center justify-center gap-2"
                >
                  {isGenerating ? <Loader2 className="animate-spin" /> : <><PlayCircle size={18} /> Generate Video Clip</>}
                </button>
              </form>
            </div>

            <div className="flex-1 bg-zinc-950 rounded-2xl border border-zinc-800 flex items-center justify-center relative overflow-hidden group">
              {isGenerating ? (
                <div className="flex flex-col items-center gap-4 text-red-500">
                    <Loader2 className="animate-spin w-12 h-12" />
                    <span className="text-sm text-zinc-400 animate-pulse text-center max-w-xs">
                      {LOADING_MESSAGES[loadingMsgIndex]}
                    </span>
                </div>
              ) : generatedVideoUrl ? (
                <>
                  <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain" />
                  <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={sendToEditor}
                        className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-full font-bold text-sm flex items-center gap-2 backdrop-blur-sm transition-colors"
                      >
                         <Scissors size={16} /> Use in Timeline
                      </button>
                      <a 
                        href={generatedVideoUrl} 
                        download={`ranktica_clip_${Date.now()}.mp4`}
                        className="bg-black/70 hover:bg-black text-white px-4 py-2 rounded-full font-bold text-sm flex items-center gap-2 backdrop-blur-sm transition-colors"
                      >
                        <Download size={16} /> Save File
                      </a>
                  </div>
                </>
              ) : (
                <div className="text-zinc-800 flex flex-col items-center gap-4">
                    <VideoIcon size={64} className="opacity-50" />
                    <p className="font-medium">Clip preview will appear here</p>
                </div>
              )}
            </div>
         </div>
       )}

       {activeTab === 'edit' && (
         <div className="flex-1 flex flex-col gap-4 overflow-hidden">
            {/* Viewer Section */}
            <div className="flex-1 bg-black rounded-xl relative flex items-center justify-center overflow-hidden border border-zinc-800 shadow-2xl">
               <video ref={previewVideoRef} className="max-h-full max-w-full" />
               <audio ref={previewAudioRef} />
               {timeline.length === 0 && (
                 <div className="text-zinc-800 flex flex-col items-center gap-4">
                    <Layers size={64} />
                    <p className="font-bold uppercase tracking-widest text-sm">Workspace Ready</p>
                 </div>
               )}
            </div>

            {/* Timeline Controls Section */}
            <div className="h-[55%] bg-zinc-900 border border-zinc-800 rounded-xl flex flex-col overflow-hidden">
               <div className="h-14 border-b border-zinc-800 flex items-center justify-between px-6 bg-zinc-950">
                  <div className="flex items-center gap-4">
                     <div className="flex items-center gap-1 bg-zinc-900 rounded-lg border border-zinc-800 p-1">
                        <button onClick={() => seek(0)} className="p-2 text-zinc-400 hover:text-white"><SkipBack size={18} /></button>
                        <button onClick={togglePlay} className="p-2 text-white hover:text-red-500 transition-colors">
                           {isPlaying ? <PauseCircle size={28} /> : <PlayCircle size={28} />}
                        </button>
                        <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-400 hover:text-white"><SkipForward size={18} /></button>
                     </div>
                     <span className="text-xs font-mono text-zinc-500 bg-zinc-900 px-3 py-1.5 rounded-lg border border-zinc-800">
                        {currentTime.toFixed(2)}s / {totalDuration.toFixed(2)}s
                     </span>
                  </div>

                  <div className="flex items-center gap-3">
                     <button 
                       onClick={() => setIsVoiceoverModalOpen(true)}
                       className="text-xs font-bold flex items-center gap-2 bg-purple-900/20 hover:bg-purple-900/40 text-purple-400 px-4 py-2 rounded-lg border border-purple-500/30 transition-all"
                     >
                       <Mic size={14} /> Add AI Voiceover
                     </button>
                     <button 
                       onClick={() => editorFileInputRef.current?.click()}
                       className="text-xs font-bold flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-lg border border-zinc-800 transition-all"
                     >
                       <Plus size={14} /> Import Media
                     </button>
                     <input type="file" ref={editorFileInputRef} onChange={handleEditorUpload} className="hidden" accept="video/*" />
                  </div>
               </div>

               <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-[#0c0c0e]">
                  {timeline.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-700 py-12">
                       <p className="text-sm font-medium">No assets in timeline. Import media or generate clips.</p>
                    </div>
                  )}

                  {timeline.map((clip) => (
                    <div key={clip.id} className="group relative bg-zinc-900/50 border border-zinc-800/80 rounded-2xl p-4 flex gap-6 items-center hover:border-zinc-700 transition-all hover:bg-zinc-900">
                       <div className={`p-4 rounded-xl shrink-0 ${clip.type === 'video' ? 'bg-blue-500/10 text-blue-500' : 'bg-purple-500/10 text-purple-500'}`}>
                          {clip.type === 'video' ? <Film size={24} /> : <AudioLines size={24} />}
                       </div>

                       <div className="flex-1 min-w-0 space-y-4">
                          <div className="flex justify-between items-start">
                             <div className="min-w-0">
                                <h4 className="text-sm font-bold text-white truncate">{clip.name}</h4>
                                <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-widest mt-0.5">{clip.type} track</p>
                             </div>
                             <div className="flex gap-2">
                                <button 
                                  onClick={() => handleSmartTrim(clip.id)}
                                  className="p-2 text-zinc-500 hover:text-yellow-500 transition-colors bg-zinc-950 rounded-lg border border-zinc-800"
                                  title="AI Magic Trim"
                                >
                                   <Zap size={14} />
                                </button>
                                <button 
                                  onClick={() => removeClip(clip.id)} 
                                  className="p-2 text-zinc-500 hover:text-red-500 transition-colors bg-zinc-950 rounded-lg border border-zinc-800"
                                  title="Delete Track"
                                >
                                   <Trash2 size={14} />
                                </button>
                             </div>
                          </div>

                          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 items-end">
                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Trim Start</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <Scissors size={10} className="text-zinc-500" />
                                   <input type="number" value={clip.trimStart} step={0.1} max={clip.trimEnd} min={0} onChange={(e) => updateClip(clip.id, { trimStart: parseFloat(e.target.value) })} className="bg-transparent border-none outline-none text-xs text-white w-full" />
                                </div>
                             </div>

                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Trim End</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <Scissors size={10} className="text-zinc-500" />
                                   <input type="number" value={clip.trimEnd} step={0.1} max={clip.duration} min={clip.trimStart} onChange={(e) => updateClip(clip.id, { trimEnd: parseFloat(e.target.value) })} className="bg-transparent border-none outline-none text-xs text-white w-full" />
                                </div>
                             </div>

                             <div className="space-y-1">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Speed</span>
                                <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-800 rounded-lg p-2">
                                   <FastForward size={10} className="text-zinc-500" />
                                   <select 
                                     value={clip.playbackSpeed} 
                                     onChange={(e) => updateClip(clip.id, { playbackSpeed: parseFloat(e.target.value) })}
                                     className="bg-transparent border-none outline-none text-xs text-white w-full cursor-pointer"
                                   >
                                      {SPEED_OPTIONS.map(s => <option key={s} value={s} className="bg-zinc-950">{s}x</option>)}
                                   </select>
                                </div>
                             </div>

                             <div className="flex flex-col justify-end text-right">
                                <span className="text-[10px] font-bold text-zinc-600 uppercase">Effective Duration</span>
                                <p className="text-xs font-mono text-zinc-300">
                                   {((clip.trimEnd - clip.trimStart) / clip.playbackSpeed).toFixed(2)}s
                                </p>
                             </div>
                          </div>

                          <div className="space-y-1.5">
                             <div className="flex justify-between text-[10px] font-bold text-zinc-600 uppercase">
                                <span>Sequence Position</span>
                                <span className="text-zinc-400">Begins @ {clip.timelineOffset.toFixed(2)}s</span>
                             </div>
                             <div className="h-2 w-full bg-zinc-950 rounded-full overflow-hidden relative border border-zinc-800">
                                <div 
                                  className={`absolute top-0 bottom-0 ${clip.type === 'video' ? 'bg-blue-600' : 'bg-purple-600'} transition-all duration-300`} 
                                  style={{ 
                                    left: `${(clip.trimStart / clip.duration) * 100}%`, 
                                    right: `${100 - (clip.trimEnd / clip.duration) * 100}%` 
                                  }}
                                ></div>
                             </div>
                          </div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
         </div>
       )}

       {/* --- VOICEOVER MODAL --- */}
       {isVoiceoverModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm animate-fade-in">
             <div className="bg-zinc-900 border border-zinc-800 rounded-[2rem] w-full max-w-2xl overflow-hidden shadow-2xl ring-1 ring-white/10">
                <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-gradient-to-r from-purple-900/20 to-transparent">
                   <div>
                      <h3 className="text-2xl font-bold text-white flex items-center gap-3"><Mic className="text-purple-500" /> AI Voice Synthesis</h3>
                      <p className="text-zinc-400 text-sm mt-1">Generate high-fidelity voiceovers for your timeline.</p>
                   </div>
                   <button onClick={() => { setIsVoiceoverModalOpen(false); setPreviewAudioUrl(null); }} className="p-2 hover:bg-zinc-800 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
                </div>

                <div className="p-8 space-y-8">
                   <div className="space-y-3">
                      <label className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Select Voice Character</label>
                      <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                         {VOICE_STYLES.map(voice => (
                            <button
                               key={voice.id}
                               onClick={() => setSelectedVoice(voice.id)}
                               className={`p-4 rounded-2xl border text-left transition-all ${
                                  selectedVoice === voice.id 
                                  ? 'bg-purple-600/10 border-purple-500 text-white shadow-lg' 
                                  : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'
                               }`}
                            >
                               <span className="block font-bold text-sm">{voice.label}</span>
                               <span className="block text-[10px] opacity-70 mt-0.5">{voice.desc}</span>
                            </button>
                         ))}
                      </div>
                   </div>

                   <div className="space-y-3">
                      <label className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Voiceover Script</label>
                      <textarea 
                         value={voiceoverText}
                         onChange={e => setVoiceoverText(e.target.value)}
                         placeholder="Enter the text for AI to speak..."
                         className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-purple-500/50 outline-none resize-none transition-all"
                      />
                   </div>

                   {previewAudioUrl && (
                      <div className="bg-zinc-950 p-4 rounded-2xl border border-zinc-800 flex items-center gap-4 animate-fade-in">
                         <div className="p-3 bg-purple-500/10 rounded-xl text-purple-400"><AudioLines size={20}/></div>
                         <div className="flex-1">
                            <span className="text-xs font-bold text-zinc-500 uppercase">Preview Ready</span>
                            <audio src={previewAudioUrl} controls className="w-full h-8 mt-1" />
                         </div>
                      </div>
                   )}

                   <div className="flex gap-4">
                      <button
                        onClick={handleGenerateVoiceoverPreview}
                        disabled={isGeneratingVoice || !voiceoverText}
                        className="flex-1 bg-zinc-800 hover:bg-zinc-700 disabled:opacity-50 text-white py-4 rounded-2xl font-bold transition-all flex items-center justify-center gap-2"
                      >
                         {isGeneratingVoice ? <Loader2 className="animate-spin" size={18} /> : <PlayCircle size={18} />}
                         {previewAudioUrl ? 'Regenerate Preview' : 'Generate Preview'}
                      </button>

                      <button
                        onClick={addVoiceoverToTimeline}
                        disabled={!previewAudioUrl}
                        className="flex-1 bg-purple-600 hover:bg-purple-500 disabled:opacity-30 disabled:cursor-not-allowed text-white py-4 rounded-2xl font-bold transition-all shadow-lg shadow-purple-600/20 flex items-center justify-center gap-2"
                      >
                         <Check size={18} /> Add to Timeline @ {currentTime.toFixed(1)}s
                      </button>
                   </div>
                </div>
             </div>
          </div>
       )}
    </div>
  );
};
